SELECT
FROM reviews r LEFT JOIN users u ON r.user_id = u.id LEFT JOIN cats c ON r.target_type = 'CAT' AND r.target_id = c.id LEFT JOIN products p ON r.target_type = 'PRODUCT' AND r.target_id = p.id LEFT JOIN orders o ON r.order_id = o.id
AND (r.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND r.target_type = #{targetType} AND r.status = #{status} AND r.rating = #{rating}
ORDER BY r.create_time DESC LIMIT #{offset}, #{pageSize}

